// Pega todos os itens recebidos
const items = $input.all();

// Extrai a UF (últimos 2 caracteres após o hífen)
const ufs = items
  .map(item => {
    const text = item.json.uf || item.json.cidade_origem || "";
    const match = text.match(/([A-Z]{2})$/);
    return match ? match[1] : null;
  })
  .filter(Boolean); // remove nulos

// Remove duplicadas
const ufsUnicas = [...new Set(ufs)];

// Retorna no formato original
return [
  {
    json: {
      ufs_unicas: ufsUnicas
    }
  }
];

